class BookMyShow {
    int n, m;
    boolean[][] seats;

    public BookMyShow(int n, int m) {
        this.n = n;
        this.m = m;
        this.seats = new boolean[n][m];
    }

    public int[] gather(int k, int maxRow) {
        for (int i = 0; i <= maxRow; i++) {
            for (int j = 0; j <= m - k; j++) {
                boolean available = true;
                for (int l = j; l < j + k; l++) {
                    if (seats[i][l]) {
                        available = false;
                        break;
                    }
                }
                if (available) {
                    for (int l = j; l < j + k; l++) {
                        seats[i][l] = true;
                    }
                    return new int[] {i, j};
                }
            }
        }
        return new int[] {};
    }

    public boolean scatter(int k, int maxRow) {
        int count = 0;
        for (int i = 0; i <= maxRow; i++) {
            for (int j = 0; j < m; j++) {
                if (!seats[i][j]) {
                    seats[i][j] = true;
                    count++;
                    if (count == k) {
                        return true;
                    }
                }
            }
        }
        for (int i = 0; i <= maxRow; i++) {
            for (int j = 0; j < m; j++) {
                if (seats[i][j]) {
                    seats[i][j] = false;
                }
            }
        }
        return false;
    }
}
